/**
 * JagotaNavigationBar
 *
 * Custom Sidebar Navigation — Jagota Design System
 * Build จาก Figma design โดยตรง (node: 61719-10625, 61719-10653, 61719-10669)
 *
 * ─── Responsive Behavior ────────────────────────────────────────────────────
 *
 *  Desktop (≥1280px)   → Expanded sidebar 240px (default)
 *  Tablet (768–1279px) → Collapsed sidebar 80px (default)
 *  Mobile (<768px)     → Top bar + Hamburger → Drawer 320px (slide-in overlay)
 *
 * ─── Interactive States (M3 standard) ───────────────────────────────────────
 *
 *  Hover:    Primary Container @ 10% overlay  — var(--state-layers/on-primary-container/opacity-10)
 *  Pressed:  Primary Container @ 16% overlay  — M3 pressed state layer
 *  Disabled: opacity 38%, cursor not-allowed, pointer-events none
 *
 * ─── Color Rules ────────────────────────────────────────────────────────────
 *
 *  ✅ ดึงสีทุกค่าจาก useTheme() — ห้าม hardcode hex ในไฟล์นี้
 *  ✅ Styled components ใช้ theme callback (({ theme }) => ...)
 *  ✅ Sub-components ใช้ useTheme() + alpha() จาก @mui/material/styles
 *
 * ─── Usage ──────────────────────────────────────────────────────────────────
 * @example
 * <JagotaAppLayout
 *   nav={
 *     <JagotaNavigationBar
 *       items={[
 *         { id: 'dashboard', label: 'Dashboard',    icon: <DashboardIcon /> },
 *         { id: 'analysis',  label: 'Analysis',     icon: <AnalyticsIcon /> },
 *         { id: 'settings',  label: 'Target Setup', icon: <SettingsIcon />, disabled: true },
 *       ]}
 *       activeId="dashboard"
 *       moduleName="Target Setup"
 *       user={{ name: 'Staff Name', role: 'Category Manager', avatarSrc: '/avatar.jpg' }}
 *       logo={<img src="/jagota-logo.svg" alt="JAGOTA" height={20} />}
 *       notificationCount={3}
 *       onNavigate={(id) => router.push(`/${id}`)}
 *     />
 *   }
 * >
 *   <PageContent />
 * </JagotaAppLayout>
 */

import React, { useState, useCallback, useEffect } from 'react'
import { styled, useTheme, alpha } from '@mui/material/styles'
import Box from '@mui/material/Box'
import Typography from '@mui/material/Typography'
import Avatar from '@mui/material/Avatar'
import Tooltip from '@mui/material/Tooltip'
import useMediaQuery from '@mui/material/useMediaQuery'

// ─────────────────────────────────────────────────────────────────────────────
// CONSTANTS — ขนาด/spacing เท่านั้น (ไม่มีสี)
// ─────────────────────────────────────────────────────────────────────────────

const SIDEBAR_EXPANDED_WIDTH  = 240   // Desktop expanded
const SIDEBAR_COLLAPSED_WIDTH = 80    // Desktop/Tablet collapsed
const MOBILE_DRAWER_WIDTH     = 320   // Mobile drawer
const MOBILE_TOPBAR_HEIGHT    = 56    // Mobile top bar height
const TABLET_BP  = 768
const DESKTOP_BP = 1280

// ─────────────────────────────────────────────────────────────────────────────
// TYPES
// ─────────────────────────────────────────────────────────────────────────────

export interface NavItem {
  id: string
  label: string
  /** Icon element — แนะนำ size 16px (ใช้ใน 24×24 box) */
  icon: React.ReactNode
  badge?: number
  /** Disabled item — แสดงแบบ dimmed (38% opacity), ไม่สามารถคลิกได้ */
  disabled?: boolean
}

export interface NavUser {
  name: string
  role: string
  avatarSrc?: string
  initials?: string
}

export interface JagotaNavigationBarProps {
  items: NavItem[]
  activeId?: string
  moduleName?: string
  /** Logo element — แนะนำ height 20px */
  logo?: React.ReactNode
  user?: NavUser
  /** จำนวน notification — desktop แสดงตัวเลข, mobile แสดงแค่ dot */
  notificationCount?: number
  onNavigate?: (id: string) => void
  onNotificationClick?: () => void
  onUserMenuClick?: () => void
  collapsed?: boolean
  onCollapsedChange?: (collapsed: boolean) => void
}

// ─────────────────────────────────────────────────────────────────────────────
// INLINE SVG ICONS — ไม่พึ่ง icon library
// ─────────────────────────────────────────────────────────────────────────────

