// ─────────────────────────────────────────────────────────────────────────────
// STYLED COMPONENTS — ดึงสีจาก theme callback (ไม่มี hardcode)
// ─────────────────────────────────────────────────────────────────────────────

const SidebarRoot = styled(Box, {
  shouldForwardProp: (p) => p !== 'isCollapsed',
})<{ isCollapsed: boolean }>(({ theme, isCollapsed }) => {
  const p = theme.palette as any
  return {
    position: 'fixed',
    top: 0,
    left: 0,
    height: '100vh',
    width: isCollapsed ? SIDEBAR_COLLAPSED_WIDTH : SIDEBAR_EXPANDED_WIDTH,
    backgroundColor: p.surface ?? theme.palette.background.paper,
    borderRight: `1px solid ${p.surfaceVariant ?? theme.palette.divider}`,
    display: 'flex',
    flexDirection: 'column',
    transition: 'width 250ms cubic-bezier(0.2, 0, 0, 1)',
    overflow: 'hidden',
    zIndex: 1200,
  }
})

const MobileTopBar = styled(Box)(({ theme }) => {
  const p = theme.palette as any
  return {
    position: 'fixed',
    top: 0,
    left: 0,
    right: 0,
    height: MOBILE_TOPBAR_HEIGHT,
    backgroundColor: p.surface ?? theme.palette.background.paper,
    borderBottom: `1px solid ${p.surfaceVariant ?? theme.palette.divider}`,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    padding: '0 16px',
    zIndex: 1200,
  }
})

// Scrim overlay — ไม่ใช่ brand color (เป็น M3 scrim standard)
const DrawerOverlay = styled(Box)({
  position: 'fixed',
  inset: 0,
  backgroundColor: 'rgba(0,0,0,0.32)',
  zIndex: 1299,
})

const DrawerPanel = styled(Box)(({ theme }) => {
  const p = theme.palette as any
  return {
    position: 'fixed',
    top: 0,
    left: 0,
    height: '100vh',
    width: MOBILE_DRAWER_WIDTH,
    backgroundColor: p.surface ?? theme.palette.background.paper,
    display: 'flex',
    flexDirection: 'column',
    zIndex: 1300,
    boxShadow: '2px 0 16px rgba(0,0,0,0.15)',   // elevation shadow — ไม่ใช่ brand color
    overflowY: 'auto',
  }
})

// ─────────────────────────────────────────────────────────────────────────────
// SUB-COMPONENTS — ทุกตัวใช้ useTheme() + alpha() แทน hardcode
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Bell button — Desktop: แสดงตัวเลข | Mobile: แสดงแค่ dot
 */
function BellButton({
  count,
  dotOnly = false,
  onClick,
}: { count?: number; dotOnly?: boolean; onClick?: () => void }) {
  const theme = useTheme()
  const p = theme.palette as any
  const surface             = p.surface ?? theme.palette.background.paper
  const onSurfaceVariant    = p.onSurfaceVariant ?? theme.palette.text.secondary
  const primaryContainer    = p.primaryContainer ?? theme.palette.primary.light
  const errorColor          = theme.palette.error.main
  const onError             = theme.palette.error.contrastText

  return (
    <Box
      component="button"
      onClick={onClick}
      aria-label={`Notifications${count ? ` (${count})` : ''}`}
      sx={{
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        width: 32, height: 32,
        borderRadius: '12px',
        border: 'none', background: 'transparent',
        cursor: 'pointer', position: 'relative',
        color: onSurfaceVariant,
        transition: 'background-color 150ms ease',
        // Interactive states
        '&:hover':  { backgroundColor: alpha(primaryContainer, 0.10) },
        '&:active': { backgroundColor: alpha(primaryContainer, 0.16) },
      }}
    >
      <BellIcon />
      {count && count > 0 ? (
        dotOnly ? (
          // Mobile: dot เล็กๆ ไม่มีตัวเลข
          <Box sx={{
            position: 'absolute', top: 2, right: 2,
            width: 6, height: 6,
            borderRadius: '50%',
            backgroundColor: errorColor,
            border: `1.5px solid ${surface}`,
          }} />
        ) : (
          // Desktop: badge มีตัวเลข
          <Box sx={{
            position: 'absolute', top: 0, right: 0,
            minWidth: 16, height: 16,
            borderRadius: '100px',
            backgroundColor: errorColor,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            px: '3px',
          }}>
            <Typography sx={{
              fontSize: 11, fontWeight: 500,
              color: onError,
              lineHeight: '16px', letterSpacing: '0.5px',
            }}>
              {count > 99 ? '99+' : count}
            </Typography>
          </Box>
        )
      ) : null}
    </Box>
  )
}

/**
 * Collapse / Expand button — bg tertiaryContainer ตาม Figma
 */
function CollapseButton({ isCollapsed, onClick }: { isCollapsed: boolean; onClick: () => void }) {
  const theme = useTheme()
  const p = theme.palette as any
  const onSurface          = p.onSurface ?? theme.palette.text.primary
  const tertiaryContainer  = p.tertiaryContainer ?? p.secondary?.light ?? theme.palette.secondary.light

  return (
    <Box
      component="button"
      onClick={onClick}
      aria-label={isCollapsed ? 'Expand sidebar' : 'Collapse sidebar'}
      sx={{
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        width: 32, height: 32,
        borderRadius: '12px',
        border: 'none',
        backgroundColor: tertiaryContainer,
        cursor: 'pointer', flexShrink: 0,
        color: onSurface,
        transition: 'background-color 150ms ease, opacity 150ms ease',
        // Interactive states
        '&:hover':  { opacity: 0.85 },
        '&:active': { opacity: 0.70 },
      }}
    >
      {isCollapsed ? <ChevronRightIcon /> : <ChevronLeftIcon />}
    </Box>
  )
}

/**
 * Menu item — Expanded state
 * Layout: [IconBox 24×24] [Label flex] [Dot 6×6 if active]
 *
 * States (M3):
 *   Default Non-selected  — transparent bg
 *   Default Selected      — surfaceContainerLow bg + primary dot
 *   Hover Non-selected    — primaryContainer @ 10% (Figma: rgba(209,214,255,0.1))
 *   Hover Selected        — surfaceContainerLow + primaryContainer @ 10% overlay
 *   Pressed Non-selected  — primaryContainer @ 16%
 *   Pressed Selected      — surfaceContainerLow + primaryContainer @ 16% overlay
 *   Disabled              — opacity 38%, pointer-events none
 */
function MenuItemExpanded({
  item, isActive, onClick,
}: { item: NavItem; isActive: boolean; onClick: () => void }) {
  const theme = useTheme()
  const p = theme.palette as any
  const surface            = p.surface ?? theme.palette.background.paper
  const surfaceContainerLow = p.surfaceContainerLow ?? theme.palette.action.selected
  const onSurfaceVariant   = p.onSurfaceVariant ?? theme.palette.text.secondary
  const primaryContainer   = p.primaryContainer ?? theme.palette.primary.light
  const primary            = theme.palette.primary.main
  const isDisabled         = item.disabled ?? false

  return (
    <Box
      component="button"
      onClick={isDisabled ? undefined : onClick}
      aria-current={isActive ? 'page' : undefined}
      aria-disabled={isDisabled || undefined}
      sx={{
        display: 'flex', alignItems: 'center',
        gap: '8px',
        width: '100%',
        padding: '12px',
        backgroundColor: isActive ? surfaceContainerLow : 'transparent',
        border: 'none',
        borderRadius: '12px',
        cursor: isDisabled ? 'not-allowed' : 'pointer',
        opacity: isDisabled ? 0.38 : 1,
        pointerEvents: isDisabled ? 'none' : 'auto',
        transition: 'background-color 150ms ease, background-image 150ms ease, opacity 150ms ease',
        // Hover — Primary Container @ 10%
        '&:hover': isActive ? {
          backgroundImage: `linear-gradient(${alpha(primaryContainer, 0.10)}, ${alpha(primaryContainer, 0.10)})`,
          backgroundColor: surfaceContainerLow,
        } : {
          backgroundColor: alpha(primaryContainer, 0.10),
        },
        // Pressed — Primary Container @ 16%
        '&:active': isActive ? {
          backgroundImage: `linear-gradient(${alpha(primaryContainer, 0.16)}, ${alpha(primaryContainer, 0.16)})`,
          backgroundColor: surfaceContainerLow,
        } : {
          backgroundColor: alpha(primaryContainer, 0.16),
        },
      }}
    >
      {/* Icon box — 24×24px surface-container-lowest rounded box */}
      <Box sx={{
        width: 24, height: 24, flexShrink: 0,
        backgroundColor: surface,
        borderRadius: '8px',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        '& svg, & .MuiSvgIcon-root': { width: 16, height: 16, fontSize: 16 },
        color: onSurfaceVariant,
      }}>
        {item.icon}
      </Box>

      {/* Label */}
      <Box sx={{ flex: 1, minWidth: 0, display: 'flex', alignItems: 'center' }}>
        <Typography sx={{
          fontSize: 12,
          fontWeight: 600,
          lineHeight: '16px',
          letterSpacing: '0.5px',
          color: onSurfaceVariant,
          whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
        }}>
          {item.label}
        </Typography>
      </Box>

      {/* Active dot — 6×6px primary color */}
      <Box sx={{
        width: 6, height: 6, flexShrink: 0,
        borderRadius: '50%',
        backgroundColor: primary,
        opacity: isActive ? 1 : 0,
        transition: 'opacity 150ms ease',
      }} />
    </Box>
  )
}

/**
 * Menu item — Collapsed state (icon only)
 * Layout: 48×48px container → inner 32×32px surface box → icon 16×16
 * Active: surfaceContainerLow bg + primary dot มุมขวาบน
 */
function MenuItemCollapsed({
  item, isActive, onClick,
}: { item: NavItem; isActive: boolean; onClick: () => void }) {
  const theme = useTheme()
  const p = theme.palette as any
  const surface            = p.surface ?? theme.palette.background.paper
  const surfaceContainerLow = p.surfaceContainerLow ?? theme.palette.action.selected
  const onSurfaceVariant   = p.onSurfaceVariant ?? theme.palette.text.secondary
  const primaryContainer   = p.primaryContainer ?? theme.palette.primary.light
  const primary            = theme.palette.primary.main
  const isDisabled         = item.disabled ?? false

  return (
    <Tooltip title={item.label} placement="right" arrow>
      <Box
        component="button"
        onClick={isDisabled ? undefined : onClick}
        aria-current={isActive ? 'page' : undefined}
        aria-disabled={isDisabled || undefined}
        sx={{
          position: 'relative',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          width: 48, height: 48,
          backgroundColor: isActive ? surfaceContainerLow : 'transparent',
          border: 'none',
          borderRadius: '12px',
          cursor: isDisabled ? 'not-allowed' : 'pointer',
          opacity: isDisabled ? 0.38 : 1,
          pointerEvents: isDisabled ? 'none' : 'auto',
          transition: 'background-color 150ms ease, background-image 150ms ease, opacity 150ms ease',
          // Hover
          '&:hover': isActive ? {
            backgroundImage: `linear-gradient(${alpha(primaryContainer, 0.10)}, ${alpha(primaryContainer, 0.10)})`,
            backgroundColor: surfaceContainerLow,
          } : {
            backgroundColor: alpha(primaryContainer, 0.10),
          },
          // Pressed
          '&:active': isActive ? {
            backgroundImage: `linear-gradient(${alpha(primaryContainer, 0.16)}, ${alpha(primaryContainer, 0.16)})`,
            backgroundColor: surfaceContainerLow,
          } : {
            backgroundColor: alpha(primaryContainer, 0.16),
          },
        }}
      >
        {/* Inner surface box — 32×32px */}
        <Box sx={{
          width: 32, height: 32,
          backgroundColor: surface,
          borderRadius: '8px',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          '& svg, & .MuiSvgIcon-root': { width: 16, height: 16, fontSize: 16 },
          color: onSurfaceVariant,
        }}>
          {item.icon}
        </Box>

        {/* Active dot — top-right (Figma: top:12, right:6) */}
        {isActive && (
          <Box sx={{
            position: 'absolute', top: 12, right: 6,
            width: 6, height: 6,
            borderRadius: '50%',
            backgroundColor: primary,
          }} />
        )}
      </Box>
    </Tooltip>
  )
}

/**
 * User footer — Expanded
 */
function UserFooterExpanded({ user, onMenuClick }: { user: NavUser; onMenuClick?: () => void }) {
  const theme = useTheme()
  const p = theme.palette as any
  const onSurface          = p.onSurface ?? theme.palette.text.primary
  const onSurfaceVariant   = p.onSurfaceVariant ?? theme.palette.text.secondary
  const outline            = p.outline ?? theme.palette.text.disabled
  const outlineVariant     = p.outlineVariant ?? theme.palette.divider
  const surfaceVariant     = p.surfaceVariant ?? theme.palette.divider
  const primaryContainer   = p.primaryContainer ?? theme.palette.primary.light
  const initials = user.initials ?? user.name.split(' ').map((n) => n[0]).join('').slice(0, 2).toUpperCase()

  return (
    <Box sx={{
      display: 'flex', alignItems: 'center', gap: '8px',
      padding: '24px',
      borderTop: `1px solid ${surfaceVariant}`,
      flexShrink: 0,
    }}>
      <Avatar
        src={user.avatarSrc} alt={user.name}
        sx={{ width: 40, height: 40, fontSize: 14, flexShrink: 0, border: `1px solid ${outlineVariant}` }}
      >
        {initials}
      </Avatar>

      <Box sx={{ flex: 1, minWidth: 0 }}>
        <Typography sx={{
          fontSize: 12, fontWeight: 600, lineHeight: '16px', letterSpacing: '0.5px',
          color: onSurface,
          whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
        }}>
          {user.name}
        </Typography>
        <Typography sx={{
          fontSize: 11, fontWeight: 500, lineHeight: '16px', letterSpacing: '0.5px',
          color: outline,
          whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
        }}>
          {user.role}
        </Typography>
      </Box>

      {/* ⋮ More menu button */}
      <Box
        component="button"
        onClick={onMenuClick}
        aria-label="User menu"
        sx={{
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          width: 32, height: 32, borderRadius: '12px',
          border: 'none', background: 'transparent',
          cursor: 'pointer', flexShrink: 0,
          color: onSurfaceVariant,
          transition: 'background-color 150ms ease',
          '&:hover':  { backgroundColor: alpha(primaryContainer, 0.10) },
          '&:active': { backgroundColor: alpha(primaryContainer, 0.16) },
        }}
      >
        <MoreVertIcon />
      </Box>
    </Box>
  )
}

/**
 * User footer — Collapsed (avatar only)
 */
function UserFooterCollapsed({ user }: { user: NavUser }) {
  const theme = useTheme()
  const p = theme.palette as any
  const surfaceVariant = p.surfaceVariant ?? theme.palette.divider
  const outlineVariant = p.outlineVariant ?? theme.palette.divider
  const initials = user.initials ?? user.name.split(' ').map((n) => n[0]).join('').slice(0, 2).toUpperCase()

  return (
    <Box sx={{
      display: 'flex', justifyContent: 'center',
      padding: '24px 8px',
      borderTop: `1px solid ${surfaceVariant}`,
      flexShrink: 0,
    }}>
      <Tooltip title={`${user.name} · ${user.role}`} placement="right" arrow>
        <Avatar
          src={user.avatarSrc} alt={user.name}
          sx={{ width: 40, height: 40, fontSize: 14, border: `1px solid ${outlineVariant}` }}
        >
          {initials}
        </Avatar>
      </Tooltip>
    </Box>
  )
}

/**
 * Expanded menu content — ใช้ร่วมกันทั้ง Sidebar และ Mobile Drawer
 */
function ExpandedMenuContent({
  items, activeId, moduleName, user,
  onNavigate, onUserMenuClick, onCollapse, showCollapseBtn = true,
}: {
  items: NavItem[]; activeId?: string; moduleName?: string; user?: NavUser
  onNavigate?: (id: string) => void; onUserMenuClick?: () => void
  onCollapse?: () => void; showCollapseBtn?: boolean
}) {
  const theme = useTheme()
  const p = theme.palette as any
  const outline = p.outline ?? theme.palette.text.disabled

  return (
    <>
      {/* Module label row */}
      {moduleName && (
        <Box sx={{
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          px: '24px', py: '12px',
          flexShrink: 0,
        }}>
          <Typography sx={{
            fontSize: 14,
            fontWeight: 500,
            lineHeight: '20px',
            letterSpacing: '0.1px',
            color: outline,
            whiteSpace: 'nowrap',
          }}>
            {moduleName}
          </Typography>
          {showCollapseBtn && (
            <CollapseButton isCollapsed={false} onClick={onCollapse ?? (() => {})} />
          )}
        </Box>
      )}

      {/* Menu list */}
      <Box sx={{
        flex: 1, overflowY: 'auto',
        px: '24px',
        pb: '24px',
        display: 'flex', flexDirection: 'column', gap: '8px',
      }}>
        {items.map((item) => (
          <MenuItemExpanded
            key={item.id}
            item={item}
            isActive={item.id === activeId}
            onClick={() => onNavigate?.(item.id)}
          />
        ))}
      </Box>

      {/* User footer */}
      {user && <UserFooterExpanded user={user} onMenuClick={onUserMenuClick} />}
    </>
  )
}

// ─────────────────────────────────────────────────────────────────────────────
// MAIN COMPONENT
// ─────────────────────────────────────────────────────────────────────────────

export function JagotaNavigationBar({
  items, activeId, moduleName, logo, user, notificationCount,
  onNavigate, onNotificationClick, onUserMenuClick,
  collapsed: collapsedProp, onCollapsedChange,
}: JagotaNavigationBarProps) {
  const theme = useTheme()
  const p = theme.palette as any
  const onSurface          = p.onSurface ?? theme.palette.text.primary
  const onSurfaceVariant   = p.onSurfaceVariant ?? theme.palette.text.secondary
  const outlineVariant     = p.outlineVariant ?? theme.palette.divider
  const surfaceVariant     = p.surfaceVariant ?? theme.palette.divider
  const primary            = theme.palette.primary.main
  const primaryContainer   = p.primaryContainer ?? theme.palette.primary.light

  const isMobile  = useMediaQuery(`(max-width:${TABLET_BP - 1}px)`)
  const isDesktop = useMediaQuery(`(min-width:${DESKTOP_BP}px)`)

  const [internalCollapsed, setInternalCollapsed] = useState(true)
  const [mobileDrawerOpen, setMobileDrawerOpen]   = useState(false)

  // Desktop: default expanded / Tablet: default collapsed
  useEffect(() => {
    setInternalCollapsed(!isDesktop)
  }, [isDesktop])

  const isCollapsed = collapsedProp !== undefined ? collapsedProp : internalCollapsed

  const handleToggle = useCallback(() => {
    const next = !isCollapsed
    setInternalCollapsed(next)
    onCollapsedChange?.(next)
  }, [isCollapsed, onCollapsedChange])

  // Logo fallback — ดึงสีจาก theme
  const DefaultLogo = (
    <Typography sx={{
      fontWeight: 700, fontSize: 20,
      color: primary,
      letterSpacing: '0.04em', lineHeight: 1,
    }}>
      JAGOTA
    </Typography>
  )

  // ── MOBILE ────────────────────────────────────────────────────────────────
  if (isMobile) {
    return (
      <>
        {/* Top Bar */}
        <MobileTopBar>
          {/* Left: Hamburger (outlined) + Logo */}
          <Box sx={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <Box
              component="button"
              onClick={() => setMobileDrawerOpen(true)}
              aria-label="Open menu"
              sx={{
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                width: 32, height: 32,
                borderRadius: '12px',
                border: `1px solid ${outlineVariant}`,   // outlined ตาม Figma
                background: 'transparent',
                cursor: 'pointer',
                color: onSurfaceVariant,
                transition: 'background-color 150ms ease',
                '&:hover':  { backgroundColor: alpha(primaryContainer, 0.10) },
                '&:active': { backgroundColor: alpha(primaryContainer, 0.16) },
              }}
            >
              <HamburgerIcon />
            </Box>
            {logo ?? DefaultLogo}
          </Box>

          {/* Right: Bell + dot badge */}
          <BellButton count={notificationCount} dotOnly={true} onClick={onNotificationClick} />
        </MobileTopBar>

        {/* Spacer ดัน content ลง */}
        <Box sx={{ height: MOBILE_TOPBAR_HEIGHT, flexShrink: 0 }} />

        {/* Overlay + Drawer */}
        {mobileDrawerOpen && (
          <>
            <DrawerOverlay onClick={() => setMobileDrawerOpen(false)} />
            <DrawerPanel>
              {/* Drawer header — Logo + × */}
              <Box sx={{
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                px: '24px',
                minHeight: 64,
                flexShrink: 0,
                borderBottom: `1px solid ${surfaceVariant}`,
              }}>
                {logo ?? DefaultLogo}
                <Box
                  component="button"
                  onClick={() => setMobileDrawerOpen(false)}
                  aria-label="Close menu"
                  sx={{
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    width: 32, height: 32, borderRadius: '12px',
                    border: 'none', background: 'transparent',
                    cursor: 'pointer', color: onSurface,
                    transition: 'background-color 150ms ease',
                    '&:hover':  { backgroundColor: alpha(primaryContainer, 0.10) },
                    '&:active': { backgroundColor: alpha(primaryContainer, 0.16) },
                  }}
                >
                  <CloseIcon />
                </Box>
              </Box>

              {/* Menu content — UI เดียวกับ Expanded sidebar */}
              <ExpandedMenuContent
                items={items} activeId={activeId} moduleName={moduleName} user={user}
                onNavigate={(id) => { onNavigate?.(id); setMobileDrawerOpen(false) }}
                onUserMenuClick={onUserMenuClick}
                showCollapseBtn={false}
              />
            </DrawerPanel>
          </>
        )}
      </>
    )
  }

  // ── DESKTOP / TABLET SIDEBAR ───────────────────────────────────────────────
  return (
    <>
      <SidebarRoot isCollapsed={isCollapsed}>

        {/* ── Header ── */}
        <Box sx={{
          display: 'flex',
          flexDirection: isCollapsed ? 'column' : 'row',
          alignItems: 'center',
          justifyContent: isCollapsed ? 'center' : 'space-between',
          px: isCollapsed ? '8px' : '24px',
          py: '16px',
          gap: isCollapsed ? '16px' : 0,
          flexShrink: 0,
          borderBottom: isCollapsed ? 'none' : `1px solid ${surfaceVariant}`,
        }}>
          {isCollapsed ? (
            // Collapsed header: Logo symbolic (J) + Bell
            <>
              <Box sx={{ width: 48, height: 48, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                <Typography sx={{
                  fontSize: 28, fontWeight: 700, color: primary,
                  fontFamily: '"TikTok Sans", "Noto Sans Thai", sans-serif',
                  lineHeight: 1,
                }}>
                  J
                </Typography>
              </Box>
              <BellButton count={notificationCount} onClick={onNotificationClick} />
            </>
          ) : (
            // Expanded header: Logo + Bell
            <>
              {logo ?? DefaultLogo}
              <BellButton count={notificationCount} onClick={onNotificationClick} />
            </>
          )}
        </Box>

        {/* ── Collapsed: Expand btn + Icon menu + User avatar ── */}
        {isCollapsed && (
          <>
            {/* Expand button > */}
            <Box sx={{ display: 'flex', justifyContent: 'center', px: '8px', pt: '8px', flexShrink: 0 }}>
              <CollapseButton isCollapsed={true} onClick={handleToggle} />
            </Box>

            {/* Icon-only menu */}
            <Box sx={{
              flex: 1, overflowY: 'auto',
              display: 'flex', flexDirection: 'column',
              alignItems: 'center',
              gap: '16px',
              px: '8px', py: '24px',
            }}>
              {items.map((item) => (
                <MenuItemCollapsed
                  key={item.id}
                  item={item}
                  isActive={item.id === activeId}
                  onClick={() => onNavigate?.(item.id)}
                />
              ))}
            </Box>

            {/* User avatar only */}
            {user && <UserFooterCollapsed user={user} />}
          </>
        )}

        {/* ── Expanded: full menu content ── */}
        {!isCollapsed && (
          <ExpandedMenuContent
            items={items} activeId={activeId} moduleName={moduleName} user={user}
            onNavigate={onNavigate} onUserMenuClick={onUserMenuClick}
            onCollapse={handleToggle} showCollapseBtn={true}
          />
        )}
      </SidebarRoot>

      {/* Content spacer — ดัน main content ออกจาก sidebar */}
      <Box sx={{
        flexShrink: 0,
        width: isCollapsed ? SIDEBAR_COLLAPSED_WIDTH : SIDEBAR_EXPANDED_WIDTH,
        transition: 'width 250ms cubic-bezier(0.2, 0, 0, 1)',
      }} />
    </>
  )
}

export default JagotaNavigationBar

// ─────────────────────────────────────────────────────────────────────────────
// JagotaAppLayout
// ─────────────────────────────────────────────────────────────────────────────

export interface JagotaAppLayoutProps {
  nav: React.ReactNode
  children: React.ReactNode
}

/**
 * Page layout wrapper — sidebar nav + main content area
 *
 * @example
 * <JagotaAppLayout nav={<JagotaNavigationBar ... />}>
 *   <PageContent />
 * </JagotaAppLayout>
 */
export function JagotaAppLayout({ nav, children }: JagotaAppLayoutProps) {
  const theme = useTheme()
  const p = theme.palette as any
  // surfaceContainerLow = page background ตาม Figma (light purple tint)
  const pageBackground = p.surfaceContainerLow ?? theme.palette.background.default

  return (
    <Box sx={{ display: 'flex', minHeight: '100vh', backgroundColor: pageBackground }}>
      {nav}
      <Box component="main" sx={{ flex: 1, minWidth: 0, overflow: 'auto' }}>
        {children}
      </Box>
    </Box>
  )
}
